        .float_ => {
// zbr:selfhost\typechecker.zbr:1956
            return true;
        },
        .bool_ => {
// zbr:selfhost\typechecker.zbr:1958
            return true;
        },
        .char_ => {
// zbr:selfhost\typechecker.zbr:1960
            return true;
        },
        .string_ => {
